{
  "name": "State Health Insurance Assistance Program (SHIP)",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; prioritizes people with limited incomes but open to all Medicare beneficiaries[1][2]",
    "asset_limits": "No asset limits or tests[1]",
    "other_requirements": ["Must be a Medicare beneficiary (age 65+ or under 65 with disabilities), their families, or caregivers[1][2][3]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free one-on-one confidential counseling, education, and assistance on Medicare Parts A/B/D, Medigap, Medicare Advantage, long-term care insurance, Medicare Savings Programs (QMB/SLMB/QI), prescription drug assistance, Medicaid, appeals, fraud prevention (via SMP), referrals, printed materials, group presentations, and help applying for cost-saving programs like Extra Help[1][2][3][4]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Toll-free 877-987-4463 or local 304-558-3317 (8:30am-5:00pm ET M-F)[3][4][5][7]", "Website: https://www.wvship.org (for info, comparisons, appointments)[3][4][9]", "In-person: At WV Bureau of Senior Services (1900 Kanawha Blvd East, 3rd Floor Town Center Mall, Charleston WV 25305) or many county senior centers and Aging & Disability Resource Centers statewide[3][4][5]", "Email: rebecca.a.gouty@wv.gov[4]"],
    "processing_time": "No formal application or processing; services provided via appointment upon contact[2][3]",
    "waitlist": null,
    "forms": ["No specific forms required; counselors assist with Medicare-related forms during sessions[1]"],
    "documents": ["Medicare card, current insurance details, prescription list, income info if applying for savings programs (counselors help gather)[2]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available statewide to WV Medicare beneficiaries[1][3][4]",
    "regional_variations": "Counselors located at county senior centers and Aging & Disability Resource Centers; no noted differences in services, wait times, or providers by region[3][5]",
    "offices_or_providers": ["Main office: 1900 Kanawha Blvd East, Charleston WV 25305[4][5]", "County senior centers statewide[3][5]"]
  },
  "official_source": "https://www.wvship.org[3][4][9]",
  "gotchas": ["Not a healthcare or financial aid program—provides counseling only, not direct payments or medical care[1][2]", "Free but requires contacting for appointment; no walk-ins guaranteed outside main office[3]", "Often confused with Medicare Savings Programs (which SHIP helps apply for); SHIP itself has no eligibility barriers[1]", "Services via local county centers may vary in availability by location[5]"],
  "data_shape_notes": "no income/asset test; counseling only, delivered via statewide network of county senior centers; prioritizes limited-income Medicare beneficiaries but open to all[1][3][5]"
}

{
  "name": "Legal Aid for Seniors (e.g., Lighthouse Program elements)",
  "eligibility": {
    "age": 60,
    "income_limits": "Financially eligible based on the LIGHTHOUSE Sliding Fee Schedule. Income may be determined by voluntary disclosure or agency estimation; no strict means test required. Specific dollar amounts not listed in sources, but designed for seniors disqualified from Medicaid by income or assets.[5][1]",
    "asset_limits": "Assets that disqualify from Medicaid services exclude eligibility for Medicaid but do not impose separate asset limits for Lighthouse; focuses on those over Medicaid thresholds.[1][5]",
    "other_requirements": [
      "Medically eligible based on functional evaluation by Aging & Family Services Registered Nurse. Two needs must be identified under Activities of Daily Living (ADL) requiring 'Much Assistance' or 'Cannot Perform'.[5]",
      "Functional needs in the home (personal care, mobility, nutrition, housekeeping).[1][5]"
    ]
  },
  "benefits": {
    "type": "service",
    "value": "In-home support in four areas: Personal Care (grooming, bathing, dressing, toileting); Mobility (transferring, walking); Nutrition (meal preparation, eating, grocery/pharmacy shopping); Environment (light housekeeping, bed making/changing, client laundry). Environmental services limited to no more than 1/3 of monthly hours. Up to 60 hours per month based on RN assessment and plan of care, provided by In-Home Care Technician.[5][1]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": [
      "Contact local senior center or provider in each county (e.g., Nicholas Community Action Partnership for Nicholas County).[1]",
      "Call Aging & Family Services at 304-788-5467.[5]",
      "County senior aging programs employ caregivers and handle intake.[1]"
    ],
    "processing_time": "Not specified in sources.",
    "waitlist": "Based on need and availability of caregivers; potential waitlist implied but not detailed.[1]",
    "forms": [
      "BoSS Intake Form (BIF) for ADL evaluation.[5]"
    ],
    "documents": [
      "Income information (voluntary disclosure or agency estimation).[5]",
      "Documentation for functional needs assessment by RN.[5]"
    ]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available in each county through local senior centers.[1][5]",
    "regional_variations": "Administered through county senior centers and local providers (e.g., Nicholas Community Action Partnership, Raleigh Seniors); services provided by local In-Home Care Technicians; potential variations in availability and wait times by county.[1][8]",
    "offices_or_providers": [
      "Senior centers in every county.[5]",
      "Aging & Family Services (304-788-5467).[5]",
      "Nicholas Community Action Partnership (local contact).[1]",
      "Raleigh Seniors (example local provider).[8]"
    ]
  },
  "official_source": "https://wvaging.com/lighthouse/",
  "gotchas": [
    "Not legal aid; provides in-home care services (personal care, etc.), not attorney services—user query mixes with West Virginia Senior Legal Aid (WVSLA), which is separate (age 60+, no income limits, call 1-800-229-5068).[2][4][5]",
    "Up to 60 hours/month only, based on RN assessment, caregiver availability, and sliding fee (may involve client cost-sharing).[1][5]",
    "Environmental services capped at 1/3 of hours; must have 2+ ADL needs at 'Much Assistance' or 'Cannot Perform' level.[5]",
    "Designed specifically for those over Medicaid income/asset limits.[1][5]"
  ],
  "data_shape_notes": "Statewide via 55 county senior centers; sliding fee scale (no fixed income table published); medically tiered by RN ADL assessment; hours capped at 60/month with service area limits; not true legal aid but in-home care for seniors ineligible for Medicaid."
}

{
  "name": "Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; services are free and available to any resident, family, or concerned party regardless of income.",
    "asset_limits": "No asset limits; no financial eligibility requirements apply.",
    "other_requirements": ["Must be a resident of a long-term care facility in West Virginia (nursing homes, assisted living facilities, residential care communities, or legally unlicensed homes), or a family member, caretaker, or concerned friend acting on behalf of such a resident."]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Investigating and resolving complaints about health, safety, welfare, and rights; routine unannounced facility visits to monitor care; providing information and referral services on long-term care options; representing residents to government agencies; educating on rights; training volunteers. All services are free and confidential.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Toll-free 1-800-834-0598 (with regional extensions, e.g., ext. 3912 for Director Ed Hopple, ext. 2812 for Martinsburg); Regional offices (e.g., 304-263-8871 ext. 2812 for Martinsburg, 304-449-4755 for Director); In-person at regional offices (e.g., 301 W. Burke St., Suite B, Martinsburg, WV 25401)"],
    "processing_time": "Complaints are investigated promptly; no fixed timeline specified, but ombudsmen address issues as they arise including on own initiative.",
    "waitlist": null,
    "forms": ["No specific application form required; contact ombudsman directly to file a complaint or request assistance."],
    "documents": ["No documents needed to initiate contact or file a complaint; provide details of the issue verbally or in writing."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Limited to residents in long-term care facilities across West Virginia; state divided into 9 regions.",
    "regional_variations": "Program operates through 9 regional ombudsmen with specific counties served and local offices; services consistent statewide but delivered by regional advocates (e.g., Brenda Alvarado serves Clay, Fayette, Nicholas, Kanawha; Mary Nicholas in Martinsburg serves Berkeley, Grant, Hampshire, Hardy, Jefferson, Mineral, Morgan, Pendleton, Preston, Tucker).",
    "offices_or_providers": ["Legal Aid of West Virginia operates the program; regional examples: Martinsburg (301 W. Burke St., Suite B), Charleston (922 Quarrier Street, 4th Floor), Morgantown (165 Scott Ave., Ste 209), Huntington (418 8th Street, Second Floor)."]
  },
  "official_source": "https://legalaidwv.org/our-programs/long-term-care/",
  "gotchas": ["This is not a direct service provider (e.g., no healthcare, housing, or financial aid); it's purely advocacy and complaint resolution. Not for general eligibility determination but for issues in facilities. Ombudsman staff are non-attorneys. Access requires facility residency or acting on behalf of one. No entry to certain facility areas without resident consent. For health facility complaints outside ombudsman scope, use OHFLAC at (304) 558-0050."],
  "data_shape_notes": "no income test; advocacy-only for long-term care facility residents; delivered via 9 regional non-attorney ombudsmen under Legal Aid WV; open to residents, families, friends without eligibility barriers."
}

{
  "name": "Lighthouse Program",
  "eligibility": {
    "age": 60,
    "income_limits": "Financially eligible based on a sliding fee scale determined by the individual's (and spouse's, if applicable) annual income. No fixed dollar amounts or household size table specified in sources; fee for services required per state cost share schedule. Means tests not required—income by voluntary disclosure or agency estimation.[2][3][5]",
    "asset_limits": "No asset test or limits mentioned. Designed for seniors whose income or assets disqualify them from Medicaid, but program itself has no financial disqualification beyond sliding fee scale.[2][4]",
    "other_requirements": [
      "West Virginia resident[3][4][7]",
      "Medically eligible based on functional evaluation by the local senior program's Registered Nurse (RN). Typically requires two needs in Activities of Daily Living (ADLs) rated as 'Much Assistance' or 'Cannot Perform' on BoSS Intake Form (BIF).[1][2][3][5][6]"
    ]
  },
  "benefits": {
    "type": "service",
    "value": "In-home supportive services in four areas: 1) Personal Care (grooming, bathing, dressing, toileting); 2) Mobility (transferring, walking); 3) Nutrition (meal preparation, eating, grocery/pharmacy shopping); 4) Environment (light housekeeping, making/changing bed, client's laundry—limited to no more than 1/3 of monthly hours). Up to 60 hours per month, based on need, RN-assessed plan of care, and caregiver availability. Provided by in-home care technicians employed by local senior programs.[2][3][4][5]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": [
      "Contact your local county senior center/program (one in each WV county) for RN evaluation and intake[3][4]",
      "Call West Virginia Bureau of Senior Services toll-free: 1-877-987-3646[3]",
      "County-specific examples: Mason County Action Group (304) 675-2369[1]; Preston County Senior Citizens (contact via site)[2]; Nicholas Community Action Partnership (contact via site)[4]; Aging & Family Services (contact via site)[5]"
    ],
    "processing_time": "Not specified in sources",
    "waitlist": "Services based on availability of caregivers; potential wait implied but not detailed[3][4]",
    "forms": [
      "BoSS Intake Form (BIF) for ADL assessment[5]"
    ],
    "documents": [
      "Income information for sliding fee determination (voluntary disclosure)[2][5]",
      "No other specific documents listed; prepare for RN functional evaluation"
    ]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available in every county of West Virginia; services provided in-home within the county[3][4][5]",
    "regional_variations": "Administered by over 140 local senior centers/programs (one per county); services uniform but delivered by different local providers with potential variations in wait times or availability based on local caregivers. Examples: Mason County Action Group, Preston County Senior Citizens, Nicholas CAP, Aging & Family Services, Raleigh Seniors.[1][2][4][5][6]",
    "offices_or_providers": ["Local county senior centers/programs (contact WV Bureau of Senior Services for your county)[3]"]
  },
  "official_source": "http://www.wvseniorservices.gov (West Virginia Bureau of Senior Services)[3]",
  "gotchas": [
    "Must pay a sliding fee based on income—not free; fee determined by state schedule[1][2][3]",
    "Limited to 60 hours/month max, based on need and caregiver availability—may not cover full needs[2][3][4]",
    "Environmental services (housekeeping) capped at 1/3 of monthly hours[5]",
    "Targeted at those ineligible for Medicaid/other programs; not a Medicaid waiver[4][5][6]",
    "Medically eligible only after RN assessment—two ADL needs typically required[5]"
  ],
  "data_shape_notes": "State-funded program delivered uniformly via 140+ local county senior centers; no strict income/asset caps but sliding fee scale; medically tiered by RN-assessed ADL needs; hours capped at 60/month with environmental services limited to 1/3"
}

{
